-- 감사 시각 관리 주체 전환: created_at/updated_at = DB 관리 (JPA Auditing 제거)
-- updated_at에 DEFAULT(INSERT 시 필수 — 엔티티가 insertable=false로 전환됨) + ON UPDATE(자동 갱신) 부여
-- ⚠️ MODIFY는 COMMENT를 재명시하지 않으면 소실됨 — V1의 원 COMMENT를 그대로 유지할 것

ALTER TABLE `member`        MODIFY `updated_at` DATETIME(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6) COMMENT '회원 정보 수정 일시';
ALTER TABLE `member_social` MODIFY `updated_at` DATETIME(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6) COMMENT '수정 일시';
